 "label": "a) Don't be late. / b) Don't late.",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) You close the door! / b) Close the door!",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) No touch it! / b) Don't touch it!",
 "prompt": "Which option is correct?"
 }
 ],
 "options": [
 "a",
 "b"
 ],
 "input_title": "Exercise 2. Create a negative form",
 "input_intro": "Turn an affirmative sentence into a negative one (with Don't).",
 "inputs": [
 {
 "before": "Open the window. ‚Üí",
 "after": ""
 },
 {
 "before": "Be loud. ‚Üí",
 "after": ""
 },
 {
 "before": "Forget your keys. ‚Üí",
 "after": ""
 }
 ],
 "rephrase_title": "Exercise 3. Error correction",
 "rephrase_intro": "Find and correct the error in the imperative sentence.",
 "rephrase": [
